  }, "\uD070 \uC77C\uC744 \uB9E1\uAE30\uBA74 \uBB54\uAC00 \uBD88\uC548\uD574\uC11C \uACC4\uC18D \uC2E0\uACBD\uC368\uC8FC\uC9C0 \uC54A\uC73C\uBA74 \uC548\uB418\uB294"), "' \uBAA8\uC2B5\uC774\uC5C8\uAE30 \uB54C\uBB38\uC774\uB2E4."), mdx("h2", null, "\uC8FC\uB2C8\uC5B4\uC640 \uC2DC\uB2C8\uC5B4\uC758 \uCC28\uC774"), mdx("p", null, "\uAC00\uC6B4\uB370 \uBC15\uC2A4 \uC548\uC744 \uCC44\uC6CC\uB123\uACE0 \uB09C \uD6C4, \uB098\uB294 \uB0B4\uAC00 \uC0DD\uAC01\uD558\uB294 \uC8FC\uB2C8\uC5B4\uC640 \uC2DC\uB2C8\uC5B4\uC758 \uCC28\uC774\uC810\uC744 \uB2E4\uC74C\uACFC \uAC19\uC774 \uC815\uB9AC\uD588\uB2E4."), mdx("ul", null, mdx("li", {
    parentName: "ul"
  }, "\uC2DC\uB2C8\uC5B4\uB294 \uAF64 \uD070 \uADDC\uBAA8\uC758 \uC18C\uD504\uD2B8\uC6E8\uC5B4 \uB514\uC790\uC778\uC744 \uD560 \uC218 \uC788\uC5B4\uC57C \uD55C\uB2E4. \uC5EC\uAE30\uC11C \uAF64 \uD070 \uADDC\uBAA8\uB77C\uB294 \uAC83\uC740 \uCD5C\uC18C\uD55C \uBE44\uC988\uB2C8\uC2A4\uC801\uC73C\uB85C \uAC00\uCE58\uB97C \uCC3D\uCD9C\uD560 \uC218 \uC788\uB294 \uC815\uB3C4\uC758 \uD504\uB85C\uC81D\uD2B8 \uADDC\uBAA8\uC774\uB2E4."), mdx("li", {
    parentName: "ul"
  }, "\uC2DC\uB2C8\uC5B4\uB294 \uD300\uC744 \uB9AC\uB529\uD560 \uC218 \uC788\uC5B4\uC57C \uD55C\uB2E4. \uC774\uB294 \uD0C0 \uC9C1\uAD70\uACFC\uC758 \uCEE4\uBBA4\uB2C8\uCF00\uC774\uC158, \uC778\uC801 \uB9AC\uC18C\uC2A4 \uAD00\uB9AC, \uC77C\uC815 \uAD00\uB9AC, \uD504\uB85C\uC81D\uD2B8 \uB9E4\uB2C8\uC9D5, \uC0DD\uC0B0\uC131, \uB3C4\uBA54\uC778\uC758 \uC774\uD574 \uB4F1\uC744 \uBAA8\uB450 \uD3EC\uAD04\uD55C\uB2E4."), mdx("li", {
