"p", null, "\uC544\uB9C8\uB3C4 \uB178\uD2B8\uC5D0 \uC801\uB294 TODO list\uAC00 \uB108\uBB34 \uB0B4 \uC5ED\uB7C9\uC744 \uACFC\uB300\uD3C9\uAC00\uD558\uC5EC \uC4F0\uC5EC\uC9C0\uAE30 \uB54C\uBB38\uC5D0 \uC790\uAFB8\uB9CC \uC644\uC218 \uBABB\uD558\uB294 \uAC83\uC774 \uC544\uB2CC\uAC00 \uC2F6\uB2E4. \uBA54\uD0C0\uC778\uC9C0\uAC00 \uB0AE\uC544\uC11C \uC0DD\uAE34 \uACB0\uACFC\uB2E4.\n\uC2A4\uC2A4\uB85C\uB97C \uB108\uBB34 \uACFC\uC2E0\uD558\uC9C0 \uB9D0\uB3C4\uB85D \uD558\uC790."), mdx("p", null, "5\uC6D4 3\uC77C\uBD80\uD130\uB294 \uC0C8\uB85C\uC6B4 \uD68C\uC0AC\uC5D0\uC11C\uC758 \uCCAB \uC2DC\uC791\uC774\uB2E4. \uBD80\uB514 \uC798 \uD5E4\uCCD0\uB098\uAC08 \uC218 \uC788\uAE38 \uBC14\uB780\uB2E4. \uCC28\uADFC\uCC28\uADFC \uC6D0\uB798\uB300\uB85C \uB3CC\uB824\uBCF4\uACA0\uB2E4."), mdx("h2", null, "5\uC6D4 \uD68C\uACE0"), mdx("p", null, "\uC0C8\uB85C\uC6B4 \uD68C\uC0AC\uC5D0\uC11C\uC758 \uD55C \uB2EC\uC744 \uBCF4\uB0C8\uB2E4. \uACB0\uACFC\uC801\uC73C\uB85C \uB098\uB294 \uCC98\uCC38\uD788 \uBB34\uB108\uC838\uB0B4\uB838\uB2E4. \uADF8\uB3D9\uC548 \uB0B4\uAC00 \uC5BC\uB9C8\uB098 \uC628\uC2E4 \uC548\uC758 \uD654\uCD08\uC600\uB294\uC9C0 \uBF08\uC800\uB9AC\uAC8C \uAE68\uB2EC\uC744 \uC218 \uC788\uB294 \uC2DC\uAC04\uC774\uC5C8\uB2E4.\n\uB09C \uAC70\uC758 \uBAA8\uB4E0 \uBD80\uBD84\uC5D0\uC11C \uD504\uB85C\uB2F5\uC9C0 \uBABB\uD588\uACE0, \uC5B4\uC124\uD504\uACE0 \uBB34\uB825\uD588\uB2E4. \uB9D0\uADC0\uB97C \uC798 \uBABB \uC54C\uC544\uB4E3\uB294 \uC0AC\uB78C\uB4E4\uC744 \uB2F5\uB2F5\uD574\uD588\uB358 \uB0B4\uAC00 \uC0C8\uB85C\uC6B4 \uD68C\uC0AC \uC548\uC5D0\uC11C \uADF8\uB7F0 \uC874\uC7AC\uAC00 \uBC14\uB85C \uB098\uB77C\uB294 \uC544\uD508 \uC0AC\uC2E4\uC774\n\uACAC\uB514\uAE30 \uD798\uB4E4\uC5C8\uB2E4. 5\uC6D4\uC774 \uB05D\uB098\uAC08 \uC988\uC74C \uB098\uB294 \uC7A0\uB3C4 \uC81C\uB300\uB85C \uBABB \uC790 \uD3D0\uC778\uC774 \uB418\uC5B4 \uD1F4\uC0AC\uD558\uACE0 \uC2F6\uB2E4\uACE0 \uC120\uC5B8\uD588\uB294\uB370, \uC120\uD0DD\uC744 \uBCF4\uB958\uD574\uB2EC\uB77C\uB294\n\uC694\uCCAD\uACFC \uD568\uAED8 \uC77C \uC8FC\uC77C \uD734\uAC00\uB97C \uBC1B\uC558\uB2E4."), mdx("p", null, "\uD734\uAC00 \uB3D9\uC548 \uB9CE\uC740 \uC0DD\uAC01\uC744 \uD588\uB2E4. \uBB34\uC5C7\uC774 \uBB38\uC81C\uC600\uC744\uAE4C. \uAE30\uC220 \uC2A4\uD0DD\uC774 \uC644\uC804\uD788 \uB2E4\uB974\uACE0 \uACBD\uB825\uC774 \uBD80\uC871\uD558\uACE0 \uC774\uB7F0 \uAC83\uC740 \uC815\uB9D0 \uBD10\uC904\uB9CC\uD55C \uD551\uACC4\uC778\uAC00?\n\uD551\uACC4\uB9CC \uB300\uACE0 \uC0B4\uBA74 \uBC1C\uC804\uC774 \uC5C6\uB2E4. \uB098\uB294 \uAC00\uC7A5 \uD070 \uC6D0\uC778\uC744 \uC695\uC2EC\uACFC \uD734\uC2DD \uBD80\uC871\uC5D0\uC11C \uCC3E\uC558\uB2E4. \uC798\uD558\uACE0 \uC2F6\uACE0 \uC798 \uBCF4\uC774\uACE0 \uC2F6\uC740 \uC695\uC2EC\uC5D0 \uB108\uBB34 \uB9CE\uC740 \uC2DC\uAC04\uC744 \uD68C\uC0AC\uC5D0 \uB0A8\uC544 \uC788\uC5C8\uB2E4.\n\uB2F9\uC2DC\uC5D0\uB294 \uBAB0\uB790\uC9C0\uB9CC \uB0B4\uAC00 \uACAA\uC5C8\uB358 \uACFC\uC815\uB4E4\uC740 \uC9C0\uAE08 \uC0DD\uAC01\uD574\uBCF4\uBA74 \uC815\uB9D0 \uC6B0\uC2A4\uAF5D\uC2A4\uB7FD\uAE30 \uC9DD\uC774 \uC5C6\uC5C8\uB2E4.\n\uADF8 \uACFC\uC815\uC740 \uB9C8\uCE58 \uC7A5\uB09C\uAC10\uC744 \uC62E\uAE30\uB294 \uB370 \uC695\uC2EC\uC774 \uB9CE\uC544\uC11C \uB450 \uD314 \uAC00\uB4DD \uC548\uACE0 \uAC00\uB2E4\uAC00 \uC804\uBD80 \uB5A8\uC5B4\uB728\uB824 \uB2E4\uC2DC \uC8FC\uC6CC \uB2F4\uC558\uB294\uB370,\n\uBA87 \uAC78\uC74C \uBABB\uAC00 \uB2E4\uC2DC \uB610 \uC804\uBD80 \uB5A8\uC5B4\uB728\uB9AC\uACE0\uB97C \uBC18\uBCF5\uD558\uB294 \uAC83\uACFC \uAC19\uC558\uB2E4.\n\uB9CE\uC774 \uC62E\uACA8\uC57C \uC798\uD55C\uB2E4\uACE0 \uC0DD\uAC01\uD560 \uD150\uB370, \uB77C\uB294 \uC0DD\uAC01 \uB54C\uBB38\uC5D0 \uC870\uBC14\uC2EC\uC774 \uB354 \uCEE4\uC9C0\uACE0 \uADF8\uAC83\uC774 \uB0B4 \uD734\uC2DD \uC2DC\uAC04\uC744 \uC557\uC544\uAC14\uB2E4. \uB098\uB97C \uB3CC\uC544\uBCFC \uC218 \uC788\uB294 \uC18C\uC911\uD55C \uADF8 \uC2DC\uAC04\uC744.\n\uBD88\uC548\uC774 \uB0A0\uC774 \uAC08 \uC218\uB85D \uCEE4\uC9C0\uC790 \uD68C\uC0AC\uB294 \uC810\uC810 \uACF5\uD3EC\uC758 \uB3C4\uAC00\uB2C8\uB85C \uBCC0\uD574\uAC14\uACE0 \uB098\uB294 \uC88C\uC808\uC744 \uB118\uC5B4 \uC808\uB9DD\uD588\uB2E4. \uB2E4\uB4E4 \uB0B4\uAC8C \uC2E4\uB9DD\uD560 \uAC83 \uAC19\uC558\uACE0, \uB0B4\uAC00 \uADF8 \uC9D1\uB2E8\uC5D0\uC11C \uC81C\uC77C \uBABB\uB098\uBCF4\uC600\uACE0\n\uB098\uB294 \uC5EC\uAE30\uC5D0 \uC5B4\uC6B8\uB9AC\uC9C0 \uC54A\uB294 \uC0AC\uB78C\uC774\uAD6C\uB098 \uC2F6\uC5C8\uB2E4. "), mdx("p", null, "\uD734\uC2DD\uD558\uB294 \uB3D9\uC548 \uB098\uB294 \uBB34\uB108\uC838\uB0B4\uB9B0 \uC790\uC874\uAC10\uC744 \uB2E4\uC2DC \uC77C\uC73C\uCF1C \uC138\uC6B0\uB294 \uB370 \uC8FC\uB825\uD588\uB2E4. \uADF8\uB9AC\uACE0 \uC65C \uB0B4\uAC00 \uC774\uB807\uAC8C \uB9E4\uBC88 \uC7A5\uB09C\uAC10\uB4E4\uC744 \uC3DF\uC544\uBC84\uB838\uB098 \uC0DD\uAC01\uD558\uB2E4\uAC00 \uB1CC\uACFC\uD559\uC744 \uC595\uAC8C \uACF5\uBD80\uD558\uAC8C \uB418\uC5C8\uB2E4.\n\uC0C8\uB85C\uC6B4 \uC9C0\uC2DD\uB4E4\uC744 \uC2B5\uB4ED\uD558\uACE0 \uC815\uB9AC\uB97C \uD558\uC9C0 \uC54A\uC544\uC11C \uB2E4 \uB5A0\uB0B4\uB824\uAC00\uBC84\uB838\uC74C\uC744 \uC774\uD574\uD588\uB2E4. \uB0B4 \uAC10\uC815\uC774 \uBD88\uC548\uC815\uD574\uC11C \uB354\uC6B1 \uC815\uBCF4 \uC2B5\uB4DD\uC774 \uB418\uC9C0 \uC54A\uC558\uB358 \uAC83\uB3C4 \uC774\uD574\uD588\uB2E4."), mdx("p", null, "\uCCAB \uBC88\uC9F8 \uBB38\uC81C\uB97C \uADF9\uBCF5\uD558\uAE30 \uC704\uD574 \uCEE8\uD14D\uC2A4\uD2B8 \uC2A4\uC704\uCE6D\uC774 \uB420 \uB54C \uB9C8\uB2E4 \uC774\uC804 \uCEE8\uD14D\uC2A4\uD2B8\uC5D0 \uB300\uD55C \uC694\uC57D \uC815\uB9AC\uB97C \uD558\uACE0\uC790 \uB9C8\uC74C \uBA39\uC5C8\uB2E4."), mdx("p", null, "\uB450 \uBC88\uC9F8 \uBB38\uC81C\uB97C \uADF9\uBCF5\uD558\uAE30 \uC704\uD574 \uD734\uC2DD\uC744 \uCDA9\uBD84\uD788 \uCDE8\uD558\uACE0 \uB0B4 \uAC10\uC815\uC744 \uC790\uC8FC \uB3CC\uC544\uBCF4\uACE0 \uD45C\uD604\uD558\uACE0\uC790 \uB9C8\uC74C \uBA39\uC5C8\uB2E4."), mdx("p", null, "\uC774 \uC678\uC5D0, \uBD80\uC871\uD55C \uB0B4 \uC5ED\uB7C9 \uADF8 \uC790\uCCB4\uC801\uC778 \uBB38\uC81C\uB97C \uADF9\uBCF5\uD558\uAE30 \uC704\uD574 \uD558\uB8E8 1\uBB38\uC81C \uC54C\uACE0\uB9AC\uC998\uC744 \uD480\uACE0 \uC8FC\uB9D0 \uC911 \uD558\uB8E8\uB294 \uAC1C\uC778\uC801\uC778 \uACF5\uBD80\uB97C \uD558\uACE0\uC790 \uB9C8\uC74C \uBA39\uC5C8\uB2E4.\n\uB9C8\uC74C \uBA39\uC740 \uB300\uB85C \uC798 \uB418\uBA74\uC57C \uBC14\uB784 \uAC8C \uC5C6\uACA0\uC9C0\uB9CC, \uADF8\uB798\uB3C4 6\uC6D4\uC740 5\uC6D4\uACFC\uB294 \uB2E4\uB974\uAE38 \uAE30\uB300\uD574\uBCF8\uB2E4. \uC815\uB9D0 \uACE0\uD1B5\uC2A4\uB7EC\uC6B4 \uD55C \uB2EC\uC774\uC5C8\uC9C0\uB9CC, \uC774\uB7F0 \uACBD\uD5D8\uC744 \uC9C0\uAE08\uC774\uB77C\uB3C4 \uD560 \uC218 \uC788\uC5B4\uC11C \uB108\uBB34\uB098\uB3C4\n\uB2E4\uD589\uC778 \uAC83 \uAC19\uB2E4."));
}
